SELECT t.TrackId, t.Name
FROM Track t
WHERE t.Composer IS NULL;

SELECT c.CustomerId, c.FirstName, c.LastName
FROM Customer c
WHERE (
    SELECT COUNT(DISTINCT STRFTIME('%Y', i.InvoiceDate))
    FROM Invoice i
    WHERE i.CustomerId = c.CustomerId
) = (
    SELECT COUNT(DISTINCT STRFTIME('%Y', i2.InvoiceDate))
    FROM Invoice i2
);
